var userConnection = Get<UserConnection>("UserConnection");
var commonInventoryService = new CommonInventoryService(userConnection);

string reservationId = Get<string>("reservationId");
string storeId = Get<string>("storeId");
string userId = Get<string>("userId");
string eventName = Get<string>("eventName");
string sourceSystem = Get<string>("sourceSystem");
Guid lineDetailId = Get<Guid>("LineDetailId");

try {
	var unreserveStock = new UnreserveStock(userConnection);
	var param = unreserveStock.GetParam(reservationId, storeId);
	
	var unreserve = commonInventoryService.Unreserve(param).GetAwaiter().GetResult();
	Set("Result", JsonConvert.SerializeObject(unreserve, Formatting.Indented));
} catch(Exception e) {
	Set("Result", e.Message);
}

return true;
